const lead = $json.body.lead;
const thread = $json.body.thread || '(no thread yet)';

const prompt = `You are an autonomous sales follow-up agent for a B2B lead management system.

Here is the full communication thread for a lead:

Lead name: ${lead.name}
Lead email: ${lead.email}
Company: ${lead.company || 'Unknown'}
Budget: $${lead.formInputs?.budget}
Timeline: ${lead.formInputs?.timelineDays} days
Score: ${lead.score}/10 (${lead.classification})
Assigned rep: ${lead.assignedRep}
Current status: ${lead.status}
Reminders sent: ${lead.remindersSent}

Communication thread:
${thread}

Your task:
1. Analyze the thread and determine who currently "has the ball" — the lead (customer hasn't replied, we are waiting on them), the staff (lead has taken an action and the rep needs to respond), or nobody (lead is closed).
2. State the single most important next action.
3. Provide a brief reasoning (2-3 sentences).
4. Draft the appropriate message — either to the lead (email) or to the assigned rep (internal note) depending on who needs to act.

Respond ONLY with valid JSON in exactly this shape:
{
  "pendingFrom": "lead" | "staff" | "none",
  "pendingAction": "<one sentence describing the immediate next action>",
  "reasoning": "<2-3 sentences explaining your analysis>",
  "draftMessage": {
    "to": "<recipient name>",
    "recipientType": "lead" | "staff",
    "subject": "<subject line>",
    "body": "<full message body>"
  }
}

If pendingFrom is "none", set draftMessage to null.`;

return [{ json: { prompt, lead, thread } }];

const raw = $json.choices[0].message.content;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    pendingFrom: 'none',
    pendingAction: 'Unable to analyze thread.',
    reasoning: 'The AI returned an unreadable response.',
    draftMessage: null
  };
}
return [{ json: parsed }];
